using System;
using System.Collections.Generic;
using UnityEngine;

[RequireComponent(typeof(PlayerMotor2D), typeof(CapsuleCollider2D), typeof(Animator))]
public class FormSwitcher : MonoBehaviour
{
    [Header("Input")]
    [SerializeField] private PlayerInputRouter input; // liga no Inspector

    [Header("Forms")]
    public AnimalFormData startingForm;
    public List<AnimalFormData> unlockedForms = new List<AnimalFormData>();

    /// <summary>
    /// Formas temporariamente bloqueadas: continuam visíveis (cinzentas) na roda
    /// de formas, mas não podem ser equipadas. Gerido pelas acções NPC
    /// Action_LockForms / Action_UnlockForms / Action_ClearFormLocks.
    /// Não persistido em save — é reposto ao carregar a cena ou via acção NPC.
    /// </summary>
    private readonly List<AnimalFormData> _lockedForms = new List<AnimalFormData>();

    /// <summary>Formas desbloqueadas que estão actualmente bloqueadas por evento de NPC (para leitura pela UI).</summary>
    public IReadOnlyList<AnimalFormData> LockedForms => _lockedForms;

    [SerializeField] private AnimalFormData currentForm;
    public AnimalFormData CurrentForm => currentForm;

    [Header("Rules")]
    [Tooltip("S� transforma se estiver no ch�o")]
    public bool requireGrounded = true;

    [Tooltip("Cooldown entre transforma��es")]
    public float transformCooldown = 10f;

    [Tooltip("Tarefa #3 - Instinto \"Ritmo Instintivo\": multiplicador aplicado ao cooldown de transformação quando este Instinto está ligado (ex.: 0.5 = cooldown reduzido a metade).")]
    [Range(0f, 1f)]
    public float ritmoInstintivoCooldownMultiplier = 0.5f;

    [Header("Fit Check (space)")]
    [Tooltip("Layers s�lidas (paredes/ch�o/teto). N�O incluir Player.")]
    public LayerMask solidLayer;

    [Header("References")]
    public WaterDetector waterDetector;

    public event Action<AnimalFormData> OnFormApplied;

    /// <summary>Disparado quando "selectedIndex" muda (navegação L/R, abertura da roda) — Roda de Animais (FormWheelUI) liga-se aqui para actualizar o destaque/ficha.</summary>
    public event Action<int> OnSelectionChanged;

    private PlayerMotor2D motor;
    private CapsuleCollider2D capsule;
    private Animator anim;
    private IFormAbility[] abilities;
    private AbilityRouter abilityRouter;

    private float cooldownTimer;

    /// <summary>Duração efectivamente usada para o cooldown em curso (transformCooldown, possivelmente reduzido pelo "Ritmo Instintivo") — denominador de TransformCooldownRemaining01.</summary>
    private float activeCooldownDuration;

    // Selec��o para a roda/atalhos
    private int selectedIndex = 0;
    private bool formWheelOpen = false;

    /// <summary>Índice actualmente seleccionado em "unlockedForms" (roda de formas — FormWheelUI lê isto para destacar o nó seleccionado).</summary>
    public int SelectedIndex => selectedIndex;

    /// <summary>True enquanto a Roda de Formas estiver aberta (entre FormWheelOpened e FormWheelClosed).</summary>
    public bool IsWheelOpen => formWheelOpen;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        capsule = GetComponent<CapsuleCollider2D>();
        anim = GetComponent<Animator>();
        abilities = GetComponents<IFormAbility>();
        abilityRouter = GetComponent<AbilityRouter>();

        if (input == null)
            input = GetComponent<PlayerInputRouter>(); // tenta auto-pegar se estiver no mesmo GO
    }

    private void Start()
    {
        if (startingForm == null)
        {
            Debug.LogError("[FormSwitcher] startingForm est� NULL. Define um AnimalFormData no Inspector.");
            enabled = false;
            return;
        }

        if (!unlockedForms.Contains(startingForm))
            unlockedForms.Insert(0, startingForm);

        // PlayerProgress.freedAnimalIds é a fonte oficial de "animais
        // libertados" (auditoria: listas duplicadas) — garante que nada fica
        // de fora caso esta lista local não tenha sido restaurada/preenchida.
        SyncFreedAnimalsFromProgress();

        // come�a no startingForm
        selectedIndex = Mathf.Clamp(0, 0, unlockedForms.Count - 1);
        ApplyForm(startingForm);
    }

    private void OnEnable()
    {
        if (input == null)
        {
            Debug.LogError("[FormSwitcher] PlayerInputRouter n�o encontrado. Liga no Inspector ou p�e no mesmo GameObject.");
            enabled = false;
            return;
        }

        input.PrevFormTapped += OnPrevForm;
        input.NextFormTapped += OnNextForm;

        input.FormWheelOpened += OnFormWheelOpened;
        input.FormWheelClosed += OnFormWheelClosed;

        input.ConfirmTransformHold += OnConfirmTransformHold;

        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.AnimalUnlocked += OnAnimalUnlocked;
    }

    private void OnDisable()
    {
        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.AnimalUnlocked -= OnAnimalUnlocked;

        if (input == null) return;

        input.PrevFormTapped -= OnPrevForm;
        input.NextFormTapped -= OnNextForm;

        input.FormWheelOpened -= OnFormWheelOpened;
        input.FormWheelClosed -= OnFormWheelClosed;

        input.ConfirmTransformHold -= OnConfirmTransformHold;
    }

    /// <summary>
    /// Reage a PlayerProgress.AnimalUnlocked (disparado por FreeAnimal):
    /// mantém unlockedForms sincronizado em tempo real com
    /// PlayerProgress.freedAnimalIds (fonte oficial), sem depender de cada
    /// chamador também lembrar de chamar UnlockForm.
    /// </summary>
    private void OnAnimalUnlocked(string formId)
    {
        var form = GameDatabase.Instance != null ? GameDatabase.Instance.FindAnimalForm(formId) : null;
        if (form == null) return;

        UnlockForm(form);

        // Tarefa #8 — sequência "Novo Animal Desbloqueado" (banner + fanfarra + animação de celebração).
        NewAnimalUnlockedUI.Instance?.Show(form);
    }

    /// <summary>
    /// Garante que toda forma já registada em PlayerProgress.freedAnimalIds
    /// (fonte oficial de "animais libertados") está presente em
    /// unlockedForms. Chamado no arranque e ao restaurar um save — evita que
    /// um animal apareça numa lista e não na outra depois de carregar uma
    /// cena.
    /// </summary>
    private void SyncFreedAnimalsFromProgress()
    {
        var progress = PlayerProgress.Instance;
        var db = GameDatabase.Instance;
        if (progress == null || db == null) return;

        foreach (var id in progress.freedAnimalIds)
        {
            var form = db.FindAnimalForm(id);
            if (form != null) UnlockForm(form);
        }
    }

    private void Update()
    {
        if (cooldownTimer > 0f)
            cooldownTimer -= Time.deltaTime;
    }

    public AnimalFormData GetCurrentForm() => currentForm;

    /// <summary>
    /// Cooldown de transformação normalizado (0 = pronto a transformar, 1 =
    /// acabou de transformar) — usado pelo HUD (Tarefa #32) para desenhar o
    /// preenchimento radial/barra sobre o ícone da forma actual.
    /// </summary>
    public float TransformCooldownRemaining01 =>
        activeCooldownDuration > 0f ? Mathf.Clamp01(cooldownTimer / activeCooldownDuration) : 0f;

    /// <summary>
    /// Aplica "form" imediatamente, sem verificar regras de transformação
    /// (chão, repouso, cooldown, fit check). Usado pelo SaveManager ao
    /// restaurar um save — assume que "form" já está em unlockedForms.
    /// </summary>
    public void ApplyFormImmediate(AnimalFormData form)
    {
        if (form == null) return;
        ApplyForm(form);
    }

    /// <summary>
    /// Adiciona "form" à lista de formas desbloqueadas (unlockedForms), se ainda
    /// não estiver lá, tornando-a seleccionável na roda de formas. Usado por
    /// Action_FreeAnimal (Etapa 5) — libertar um animal em PlayerProgress não é,
    /// por si só, suficiente para o player conseguir transformar-se nele.
    /// </summary>
    public bool UnlockForm(AnimalFormData form)
    {
        if (form == null) return false;
        if (unlockedForms.Contains(form)) return false;

        unlockedForms.Add(form);
        return true;
    }

    // UI/radial pode chamar isto directamente
    public void SetSelectedIndex(int idx)
    {
        if (unlockedForms.Count == 0) return;
        selectedIndex = Mathf.Clamp(idx, 0, unlockedForms.Count - 1);
        OnSelectionChanged?.Invoke(selectedIndex);
    }

    public void TrySwitchToSelected()
    {
        if (unlockedForms.Count == 0) return;
        TrySwitchTo(unlockedForms[selectedIndex]);
    }

    public void TrySwitchToIndex(int idx)
    {
        if (idx < 0 || idx >= unlockedForms.Count) return;
        selectedIndex = idx;
        TrySwitchToSelected();
    }

    /// <summary>
    /// Verifica se "target" pode ser activada AGORA, sem aplicar nada —
    /// aplica as mesmas regras de ambiente do GDD 4.1 que <see cref="TrySwitchTo"/>
    /// (chão/água/submerso, cooldown, bloqueios gerais, fit check). Usado pela
    /// Roda de Formas (FormWheelUI) para acinzentar formas indisponíveis e
    /// mostrar o motivo (<paramref name="reason"/>) sem precisar de tentar
    /// transformar. "target" sendo a forma actual devolve true (não há motivo
    /// para acinzentar a forma já equipada — a UI trata "forma actual" como
    /// caso especial de destaque, não de bloqueio).
    /// </summary>
    public bool CanSwitchTo(AnimalFormData target, out string reason)
    {
        reason = null;

        if (target == null)
        {
            reason = "Forma inválida.";
            return false;
        }

        if (target == currentForm)
            return true;

        if (cooldownTimer > 0f)
        {
            reason = "Ainda a recuperar da transformação.";
            return false;
        }

        // Bloqueios gerais (GDD 4.1): em knockback, a tomar dano, preso por
        // armadilha ou agarrado à parede — todos representados por
        // motor.MovementLocked (já usado por ClimbAbility/DashAbility/etc.;
        // futuros sistemas de dano/knockback/armadilha do player devem chamar
        // motor.SetMovementLocked(true, this) enquanto durar o efeito, e
        // SetMovementLocked(false, this) no fim — ver PlayerMotor2D para o
        // porquê do "this").
        if (motor.MovementLocked)
        {
            reason = "Não podes transformar agora.";
            return false;
        }

        // Desafio com forma bloqueada (requiredForm no ChallengeTrigger ou
        // lockFormDuringChallenge na ChallengeDefinition): o player só pode
        // usar o animal com que entrou no desafio.
        if (ChallengeManager.Instance != null && ChallengeManager.Instance.IsFormSwitchingLocked)
        {
            reason = "Não podes trocar de forma durante este desafio.";
            return false;
        }

        // Forma temporariamente bloqueada por evento de NPC (aparece cinzenta na roda).
        if (IsFormLocked(target))
        {
            reason = "Esta forma está temporariamente bloqueada.";
            return false;
        }

        bool inWater = (waterDetector != null && waterDetector.IsInWater);
        bool submerged = (waterDetector != null && waterDetector.IsSubmerged);

        bool targetIsAquatic = (target.movementMode == MovementMode.SwimOnly) || (target.swimType != SwimType.None);
        bool targetCanDive = target.swimType == SwimType.Underwater;

        if (requireGrounded)
        {
            bool onLand = motor.IsGrounded && !inWater;
            bool inAir = !motor.IsGrounded && !inWater;

            // Recompensa de Pós-Jogo (GDD): permite transformar no ar, mas
            // mantém as regras de formas aquáticas/terrestres abaixo.
            bool postGameFreeTransform = PlayerProgress.Instance != null && PlayerProgress.Instance.IsPostGameRewardActive;

            // No ar (sem chão e sem água): nenhuma transformação, a menos que
            // a Recompensa de Pós-Jogo esteja activa.
            if (inAir && !postGameFreeTransform)
            {
                reason = "Não podes transformar no ar.";
                return false;
            }

            if (submerged)
            {
                // Submerso: só formas aquáticas capazes de mergulhar (swimType == Underwater).
                if (!targetCanDive)
                {
                    reason = "Estás debaixo de água. Só podes transformar em formas capazes de mergulhar.";
                    return false;
                }
            }
            else if ((onLand || inAir) && targetIsAquatic && !target.canActOnLand)
            {
                // Em terra (ou no ar, com a Recompensa de Pós-Jogo): terrestres,
                // ou aquáticos marcados "Pode actuar em terra?" (anfíbios).
                reason = "Essa forma só pode ser usada na água.";
                return false;
            }
            // Superfície da água (inWater && !submerged): ponto de transição —
            // terrestres ou aquáticos, sem restrição extra.

            // Nota (auditoria): havia aqui um bloqueio extra por velocidade
            // (motor.RB.velocity.magnitude > 0.15) para exigir "repouso". O
            // GDD trata "repouso" como um ESTADO permitido (correr numa
            // plataforma, deslizar ligeiramente no gelo, etc.), não como
            // velocidade ~zero — esse threshold bloqueava transformações
            // válidas. Os estados que devem mesmo bloquear (knockback, stun,
            // dash, escalar, balanço, língua, armadilha, morte, diálogo...)
            // já são cobertos por motor.MovementLocked, verificado acima.
        }

        // Fit check
        if (!CanFit(target))
        {
            reason = "Não há espaço para essa transformação.";
            return false;
        }

        return true;
    }

    /// <summary>
    /// Tenta transformar para "target": valida via <see cref="CanSwitchTo"/> e,
    /// se possível, aplica a forma e inicia o cooldown. Se não for possível,
    /// mostra o motivo (Feedback) — ver CanSwitchTo para as regras completas
    /// (GDD 4.1: chão/água/submerso, cooldown, bloqueios gerais, fit check).
    /// </summary>
    public void TrySwitchTo(AnimalFormData target)
    {
        if (target == null) return;
        if (target == currentForm) return;

        if (!CanSwitchTo(target, out string reason))
        {
            Feedback(reason);
            return;
        }

        ApplyForm(target);

        // Tarefa #3: o Instinto "Ritmo Instintivo" reduz o cooldown de
        // transformação (multiplicador configurável no Inspector).
        float cooldown = transformCooldown;
        if (PlayerProgress.Instance != null && PlayerProgress.Instance.IsRitmoInstintivoActive)
            cooldown *= ritmoInstintivoCooldownMultiplier;

        // Recompensa de Pós-Jogo (GDD): cooldown de transformação zero.
        if (PlayerProgress.Instance != null && PlayerProgress.Instance.IsPostGameRewardActive)
            cooldown = 0f;

        cooldownTimer = cooldown;
        activeCooldownDuration = cooldown;
    }

    private void ApplyForm(AnimalFormData form)
    {
        currentForm = form;

        // 0) cancela qualquer habilidade "com estado" activa (escalar, dash,
        // balanço, língua, escudo, carregar objecto, ...) ANTES de mudar de
        // forma — a forma nova pode não ter as mesmas habilidades/colliders,
        // por isso estas precisam de se desfazer (gravidade, locks de
        // movimento, etc.) com a forma ainda antiga (item 8 da auditoria).
        if (abilityRouter != null)
            abilityRouter.CancelAll(AbilityCancelReason.Transform);

        // 1) aplica stats no motor (inclui collider e ground check)
        motor.ApplyForm(form);

        // 2) anima��o (override por animal)
        if (form.overrideController != null)
            anim.runtimeAnimatorController = form.overrideController;

        // 3) reconfigura todas as habilidades modulares (Dash, Charge, Roll, etc.)
        foreach (var ability in abilities)
            ability.ConfigureFromForm(form);

        OnFormApplied?.Invoke(form);

        Feedback($"Transformado: {form.displayName}");
    }

    // Buffer reutilizável para CanFit (evita alocar array a cada transformação).
    private readonly Collider2D[] _fitBuffer = new Collider2D[1];

    private bool CanFit(AnimalFormData target)
    {
        bool wasEnabled = capsule.enabled;
        capsule.enabled = false;

        try
        {
            Vector2 worldPos = (Vector2)transform.position + target.colliderOffset;

            // ContactFilter2D com useTriggers=false: ignora colliders marcados
            // como Trigger em "solidLayer" (ex: zonas de água/detectores que por
            // engano partilhem a layer sólida), evitando falsos bloqueios/CanFit
            // incorrecto. Só colliders sólidos (não-trigger) contam para o fit check.
            var filter = new ContactFilter2D();
            filter.SetLayerMask(solidLayer);
            filter.useTriggers = false;

            int hitCount = Physics2D.OverlapCapsule(
                worldPos,
                target.colliderSize,
                CapsuleDirection2D.Vertical,
                0f,
                filter,
                _fitBuffer
            );

            return hitCount == 0;
        }
        finally
        {
            capsule.enabled = wasEnabled;
        }
    }

    // -------- Input callbacks --------

    private void OnPrevForm()
    {
        // Com o jogo em pausa, L/R pertencem à navegação de secções do Menu de
        // Pausa (PauseMenuController) — não trocar de forma.
        if (GamePauseUtil.IsPaused) return;

        if (unlockedForms.Count == 0) return;

        // Se estiver na roda, s� muda sele��o (UI). Se n�o, pode trocar directo (tu escolhes o feeling).
        selectedIndex = (selectedIndex - 1 + unlockedForms.Count) % unlockedForms.Count;
        OnSelectionChanged?.Invoke(selectedIndex);

        if (!formWheelOpen)
            TrySwitchToSelected();
        // se wheelOpen, s� highlight no UI
    }

    private void OnNextForm()
    {
        // Com o jogo em pausa, L/R pertencem à navegação de secções do Menu de
        // Pausa (PauseMenuController) — não trocar de forma.
        if (GamePauseUtil.IsPaused) return;

        if (unlockedForms.Count == 0) return;

        selectedIndex = (selectedIndex + 1) % unlockedForms.Count;
        OnSelectionChanged?.Invoke(selectedIndex);

        if (!formWheelOpen)
            TrySwitchToSelected();
    }

    private void OnFormWheelOpened()
    {
        formWheelOpen = true;

        // opcional: quando abre a roda, selecciona o form actual
        int idx = unlockedForms.IndexOf(currentForm);
        if (idx >= 0) selectedIndex = idx;

        OnSelectionChanged?.Invoke(selectedIndex);
    }

    private void OnFormWheelClosed()
    {
        formWheelOpen = false;
    }

    private void OnConfirmTransformHold()
    {
        // S� faz sentido quando a roda est� aberta (se quiseres)
        if (!formWheelOpen) return;

        TrySwitchToSelected();
    }

    private void Feedback(string msg)
    {
        Debug.Log($"[FormSwitcher] {msg}");
    }

    // ---------------- Bloqueio Temporário de Formas (Eventos NPC) ----------------

    /// <summary>
    /// Disparado quando a lista de formas bloqueadas muda — a roda de formas
    /// (FormWheelUI) subscreve aqui para actualizar os nós cinzentos em tempo real.
    /// </summary>
    public event System.Action LockedFormsChanged;

    /// <summary>
    /// True se "form" está na lista de bloqueadas (visível na roda mas não seleccionável).
    /// </summary>
    public bool IsFormLocked(AnimalFormData form) =>
        form != null && _lockedForms.Contains(form);

    /// <summary>
    /// Bloqueia "form" temporariamente: continua visível (cinzenta) na roda mas
    /// não pode ser equipada. Sem efeito se a forma já estiver bloqueada.
    /// Se o player estiver actualmente nessa forma, NÃO força saída — o designer
    /// deve tirar a forma (ou usar Action_SaveAndRemoveForms) antes de bloquear
    /// se quiser que o player saia dela.
    /// </summary>
    public void LockForm(AnimalFormData form)
    {
        if (form == null || _lockedForms.Contains(form)) return;
        // A forma base (Íris) nunca pode ser bloqueada.
        if (form == startingForm)
        {
            Debug.LogWarning("[FormSwitcher] Tentativa de bloquear a startingForm (Íris) — operação bloqueada.");
            return;
        }
        _lockedForms.Add(form);
        LockedFormsChanged?.Invoke();
    }

    /// <summary>
    /// Remove "form" da lista de bloqueadas, tornando-a novamente seleccionável.
    /// Sem efeito se não estava bloqueada.
    /// </summary>
    public void UnlockFormLock(AnimalFormData form)
    {
        if (form == null) return;
        if (_lockedForms.Remove(form))
            LockedFormsChanged?.Invoke();
    }

    /// <summary>
    /// Remove todos os bloqueios temporários, restaurando todas as formas
    /// desbloqueadas como seleccionáveis. Útil no final de uma área de evento.
    /// </summary>
    public void ClearAllFormLocks()
    {
        if (_lockedForms.Count == 0) return;
        _lockedForms.Clear();
        LockedFormsChanged?.Invoke();
    }

    // ---------------- Remoção Temporária (Íris Fallback) ----------------

    /// <summary>
    /// Formas removidas temporariamente de <see cref="unlockedForms"/>
    /// (ex: sequências narrativas onde o player perde os animais).
    /// Guardadas aqui para serem restauradas depois via
    /// <see cref="RestoreRemovedForm"/> / <see cref="RestoreAllRemovedForms"/>.
    /// </summary>
    private readonly List<AnimalFormData> _temporarilyRemovedForms = new List<AnimalFormData>();

    /// <summary>
    /// Remove "form" de <see cref="unlockedForms"/> temporariamente — a forma
    /// desaparece da roda e não pode ser equipada. Se era a forma actual,
    /// o player reverte para <see cref="startingForm"/> (Íris). Se não for
    /// encontrada em unlockedForms, não faz nada.
    ///
    /// Chamar <see cref="RestoreRemovedForm"/> ou
    /// <see cref="RestoreAllRemovedForms"/> para reverter.
    /// </summary>
    public void RemoveFormTemporarily(AnimalFormData form)
    {
        if (form == null) return;
        // A forma base (Íris / startingForm) nunca pode ser removida — é o
        // fallback do jogo e removê-la quebraria a progressão.
        if (form == startingForm)
        {
            Debug.LogWarning("[FormSwitcher] Tentativa de remover a startingForm (Íris) temporariamente — operação bloqueada.");
            return;
        }
        if (!unlockedForms.Contains(form)) return;
        if (_temporarilyRemovedForms.Contains(form)) return;

        _temporarilyRemovedForms.Add(form);
        unlockedForms.Remove(form);

        // Se o jogador estava nessa forma, volta para startingForm.
        if (currentForm == form)
        {
            var fallback = startingForm;
            if (fallback == null && unlockedForms.Count > 0) fallback = unlockedForms[0];
            if (fallback != null)
                ApplyForm(fallback);
            else
            {
                // Nenhuma forma disponível: forçar currentForm a null explicitamente
                // para evitar referência solta à forma removida.
                currentForm = null;
                selectedIndex = -1;
            }
        }

        // Corrige selectedIndex após a remoção.
        if (unlockedForms.Count > 0)
            selectedIndex = Mathf.Clamp(selectedIndex, 0, unlockedForms.Count - 1);
        else if (selectedIndex != -1)
            selectedIndex = -1;
    }

    /// <summary>
    /// Restaura "form" que foi removida via
    /// <see cref="RemoveFormTemporarily"/>, devolvendo-a a
    /// <see cref="unlockedForms"/>. Sem efeito se não estava na lista de removidas.
    /// </summary>
    public void RestoreRemovedForm(AnimalFormData form)
    {
        if (form == null) return;
        if (!_temporarilyRemovedForms.Remove(form)) return;

        if (!unlockedForms.Contains(form))
            unlockedForms.Add(form);
    }

    /// <summary>
    /// Restaura todas as formas removidas temporariamente, devolvendo-as a
    /// <see cref="unlockedForms"/>. Útil no fim de uma sequência narrativa.
    /// </summary>
    public void RestoreAllRemovedForms()
    {
        foreach (var form in _temporarilyRemovedForms)
            if (form != null && !unlockedForms.Contains(form))
                unlockedForms.Add(form);

        _temporarilyRemovedForms.Clear();
    }

    /// <summary>
    /// Devolve true se "form" foi removida temporariamente via
    /// <see cref="RemoveFormTemporarily"/> (útil para verificar estado em
    /// condições de missão/eventos).
    /// </summary>
    public bool IsTemporarilyRemoved(AnimalFormData form) =>
        form != null && _temporarilyRemovedForms.Contains(form);

    /// <summary>
    /// Devolve uma cópia dos IDs das formas actualmente bloqueadas — para guardar
    /// num snapshot (Task #5) e restaurar mais tarde.
    /// </summary>
    public List<string> CaptureLockedFormIds()
    {
        var ids = new List<string>(_lockedForms.Count);
        foreach (var f in _lockedForms)
            if (f != null && !string.IsNullOrEmpty(f.formId))
                ids.Add(f.formId);
        return ids;
    }

    /// <summary>
    /// Restaura bloqueios a partir de uma lista de IDs (guardada num snapshot).
    /// Substitui os bloqueios actuais.
    /// </summary>
    public void RestoreLockedFormIds(List<string> ids)
    {
        _lockedForms.Clear();
        if (ids != null)
        {
            var db = GameDatabase.Instance;
            foreach (var id in ids)
            {
                var form = db != null ? db.FindAnimalForm(id) : null;
                if (form != null && !_lockedForms.Contains(form))
                    _lockedForms.Add(form);
            }
        }
        LockedFormsChanged?.Invoke();
    }

    // ---------------- Save / Load ----------------

    /// <summary>Copia formas desbloqueadas e forma actual para "data" (usado por SaveManager ao gravar).</summary>
    public void CaptureTo(SaveData data)
    {
        data.unlockedFormIds = new List<string>();
        foreach (var form in unlockedForms)
            if (form != null && !string.IsNullOrEmpty(form.formId))
                data.unlockedFormIds.Add(form.formId);

        data.currentFormId = currentForm != null ? currentForm.formId : null;
    }

    /// <summary>
    /// Restaura formas desbloqueadas e forma actual a partir de "data" (usado
    /// por SaveManager ao carregar). Os formIds são resolvidos via
    /// GameDatabase; formas não encontradas são ignoradas.
    /// </summary>
    public void RestoreFrom(SaveData data)
    {
        if (data == null) return;

        var db = GameDatabase.Instance;

        unlockedForms.Clear();
        if (data.unlockedFormIds != null && db != null)
        {
            foreach (var id in data.unlockedFormIds)
            {
                var form = db.FindAnimalForm(id);
                if (form != null) unlockedForms.Add(form);
            }
        }

        if (unlockedForms.Count == 0 && startingForm != null)
            unlockedForms.Add(startingForm);

        // Garante consistência com PlayerProgress.freedAnimalIds (fonte
        // oficial) — ver SyncFreedAnimalsFromProgress.
        SyncFreedAnimalsFromProgress();

        AnimalFormData target = db != null ? db.FindAnimalForm(data.currentFormId) : null;
        if (target == null) target = startingForm;
        if (target == null && unlockedForms.Count > 0) target = unlockedForms[0];

        if (target != null)
        {
            selectedIndex = Mathf.Max(0, unlockedForms.IndexOf(target));
            ApplyFormImmediate(target);
        }
    }
}
